const { randomUUID } = require('node:crypto');

let commentsStore = [];

async function createComment(message) {
  const commentId = randomUUID();
  const comment = { id: commentId, message };
  commentsStore.push(comment);
  return comment;
}

module.exports = {
  createComment,
};
